const rawYesBids: [string, string][] = book.yes_dollars || book.yes || [];
const rawNoBids: [string, string][] = book.no_dollars || book.no || [];

// Parse to numeric [price_decimal, quantity]
const yesBids: [number, number][] = rawYesBids
  .map(([p, q]): [number, number] => [parseFloat(p), parseFloat(q)])
  .sort((a, b) => b[0] - a[0]); // best (highest) bid first
const noBids: [number, number][] = rawNoBids
  .map(([p, q]): [number, number] => [parseFloat(p), parseFloat(q)])
  .sort((a, b) => b[0] - a[0]);

// Derive YES asks from NO bids: YES ask = 1 - NO bid price
const yesAsks: [number, number][] = noBids
  .map(([p, q]): [number, number] => [1 - p, q])
  .sort((a, b) => a[0] - b[0]); // best (lowest) ask first

// Derive NO asks from YES bids: NO ask = 1 - YES bid price
const noAsks: [number, number][] = yesBids
  .map(([p, q]): [number, number] => [1 - p, q])
  .sort((a, b) => a[0] - b[0]);

// Select relevant book side
const relevantAsks = side === 'YES' ? yesAsks : noAsks;
const relevantBids = side === 'YES' ? yesBids : noBids;

// Sum top 3 levels
const topAskSize = relevantAsks.slice(0, 3).reduce((s, [, q]) => s + q, 0);
const topBidSize = relevantBids.slice(0, 3).reduce((s, [, q]) => s + q, 0);

const bestAsk = relevantAsks[0]?.[0] ?? null;
const bestBid = relevantBids[0]?.[0] ?? null;
const spread = bestAsk !== null && bestBid !== null ? Math.round((bestAsk - bestBid) * 100) : null;

