1	/**
2	 * Paper trading tracker.
3	 * Logs simulated trades based on signals, then checks settled markets
4	 * to calculate theoretical P&L without risking real money.
5	 */
6	import fs from 'fs';
7	import path from 'path';
8	import axios from 'axios';
9	
10	const DATA_DIR = path.join(__dirname, '..', 'data');
11	const PAPER_FILE = path.join(DATA_DIR, 'paper-trades.json');
12	
13	export interface PaperTrade {
14	  id: number;
15	  city: string;
16	  target_date: string;
17	  ticker: string;
18	  side: 'YES' | 'NO';
19	  entry_price: number;           // what we would have paid
20	  simulated_contracts: number;   // Kelly-sized contracts
21	  simulated_cost: number;        // entry_price * contracts
22	  forecast_high_f: number;
23	  implied_temp_f: number;
24	  gap_f: number;
25	  kelly_fraction?: number;       // raw Kelly fraction before halving
26	  model_spread?: number;         // spread between forecast models (°F)
27	  model_confidence?: 'high' | 'medium' | 'low';
28	  ensemble_pwin?: number;
29	  ensemble_std?: number;
30	  ensemble_members?: number;
31	  liquidity_ok?: boolean;
32	  spread_cents?: number | null;
33	  status: 'open' | 'won' | 'lost' | 'expired';
34	  settlement_value?: string;     // actual temp recorded
35	  pnl?: number;                  // profit/loss in dollars
36	  created_at: string;
37	  settled_at?: string;
38	}
39	
40	const PAPER_BANKROLL = 1000;      // simulated bankroll for Kelly sizing
41	const KELLY_FRACTION = 0.5;     // half-Kelly for safety
42	const MIN_CONTRACTS = 5;
43	const MAX_CONTRACTS = 50;
44	
45	/**
46	 * Estimate win probability based on edge (gap) and model spread.
47	 */
48	function estimateWinProbability(gapF: number, spread: number | null): number {
49	  const absGap = Math.abs(gapF);
50	  const s = spread ?? 999; // treat unknown spread as low confidence
51	
52	  if (absGap >= 5 && s <= 2) return 0.72;
53	  if (absGap >= 3 && s <= 2) return 0.65;
54	  if (absGap >= 3 && s <= 4) return 0.58;
55	  if (absGap >= 2 && s <= 2) return 0.60;
56	  return 0.55;
57	}
58	
59	/**
60	 * Calculate half-Kelly position size.
61	 * Returns { contracts, kellyFraction } or null if no edge (negative Kelly).
62	 */
63	function kellySize(entryPrice: number, gapF: number, spread: number | null, pWinOverride?: number): { contracts: number; kellyFraction: number } | null {
64	  const pWin = pWinOverride ?? estimateWinProbability(gapF, spread);
65	  const odds = (1 / entryPrice) - 1; // net odds (e.g. price=0.40 → odds=1.5)
66	  const kellyFraction = (pWin * odds - (1 - pWin)) / odds;
67	
68	  if (kellyFraction <= 0) return null; // no edge — skip trade
69	
70	  const halfKelly = kellyFraction * KELLY_FRACTION;
71	  const dollarSize = halfKelly * PAPER_BANKROLL;
72	  const contracts = Math.floor(dollarSize / entryPrice);
73	  const clamped = Math.max(MIN_CONTRACTS, Math.min(MAX_CONTRACTS, contracts));
74	
75	  return { contracts: clamped, kellyFraction };
76	}
77	
78	function ensureDataDir() {
79	  if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });
80	}
81	
82	function readTrades(): PaperTrade[] {
83	  ensureDataDir();
84	  try {
85	    if (fs.existsSync(PAPER_FILE)) return JSON.parse(fs.readFileSync(PAPER_FILE, 'utf8'));
86	  } catch { /* ignore */ }
87	  return [];
88	}
89	
90	function writeTrades(trades: PaperTrade[]) {
91	  fs.writeFileSync(PAPER_FILE, JSON.stringify(trades, null, 2));
92	}
93	
94	/**
95	 * Log a paper trade with Kelly-sized position.
96	 * Returns null if Kelly says no edge (negative fraction) — trade is skipped.
97	 */
98	export function logPaperTrade(
